const company = $.input.sourceCompany || '';
const url = $.input.sourceCompanyUrl || '';
const query = 'Companies that compete with ' + company + ' in the same market and industry, alternatives to ' + company;
return { query, company, url };

const response = $.steps.exaSearch.response || {};
const results = response.data?.results || response.results || [];
const sourceCompany = $.input.sourceCompany.toLowerCase();
const competitors = [];
const seen = {};

results.forEach(function(r) {
  const url = r.url || '';
  const domain = url.replace(/https?:\/\//, '').replace(/www\./, '').split('/')[0];
  if (domain && !seen[domain] && domain.indexOf(sourceCompany.replace(/\s/g, '')) < 0) {
    seen[domain] = true;
    competitors.push({
      name: r.title || domain,
      url: 'https://' + domain,
      snippet: (r.text || '').slice(0, 500)
    });
  }
});

return { competitors: competitors.slice(0, $.input.maxCompetitors || 5), count: competitors.length };

const competitors = $.steps.parseCompetitors.output.competitors;
const iterations = $.steps.scrapeCompetitors.response?.iterations || [];
let allData = '';

competitors.forEach(function(comp, i) {
  const iter = iterations[i] || {};
  const resp = iter.scrapeWebsite?.response?.data || iter.scrapeWebsite?.response || {};
  const content = (resp.markdown || resp.content || comp.snippet || '').slice(0, 3000);
  allData += '=== COMPETITOR ' + (i + 1) + ': ' + comp.name + ' ===\n';
  allData += 'URL: ' + comp.url + '\n';
  allData += 'Content:\n' + content + '\n\n';
});

return { allData: allData, source: $.input.sourceCompany, competitorCount: competitors.length };

const data = $.steps.compileAllData.output;

let prompt = 'You are a competitive intelligence analyst. Analyze the following competitors of ' + data.source + '. For each competitor, act as three specialized agents:\n';
prompt += '1. Company Overview Agent - extract company basics, market, size, funding\n';
prompt += '2. Product Offering Agent - identify products, features, pricing tiers\n';
prompt += '3. Market Position Agent - analyze strengths, weaknesses, differentiation\n\n';
prompt += 'COMPETITORS DATA:\n' + data.allData + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "sourceCompany": "' + data.source + '",\n';
prompt += '  "competitors": [\n';
prompt += '    {\n';
prompt += '      "name": "company name",\n';
prompt += '      "url": "website url",\n';
prompt += '      "overview": { "industry": "", "market": "B2B/B2C", "founded": "", "size": "", "summary": "" },\n';
prompt += '      "products": { "mainProducts": [""], "features": [""], "pricing": "" },\n';
prompt += '      "position": { "strengths": [""], "weaknesses": [""], "differentiation": "" }\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "marketInsights": "overall competitive landscape summary",\n';
prompt += '  "opportunities": ["opportunity for source company"]\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { sourceCompany: $.input.sourceCompany, competitors: [], marketInsights: raw.slice(0, 500), opportunities: [] }; }

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Competitor Research: ' + (ai.sourceCompany || $.input.sourceCompany), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Competitors Found:* ' + ((ai.competitors || []).length) } });
blocks.push({ type: 'divider' });

const comps = ai.competitors || [];
comps.slice(0, 5).forEach(function(c) {
  let text = '*' + (c.name || 'Unknown') + '* - <' + (c.url || '#') + '|Website>\n';
  if (c.overview) text += c.overview.summary + '\n';
  if (c.position && c.position.differentiation) text += '_Differentiation:_ ' + c.position.differentiation + '\n';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

blocks.push({ type: 'divider' });
if (ai.marketInsights) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Market Insights:*\n' + ai.marketInsights.slice(0, 1500) } });
}
if (ai.opportunities && ai.opportunities.length > 0) {
  let oppText = '*Opportunities:*\n';
  ai.opportunities.slice(0, 5).forEach(function(o, i) { oppText += (i + 1) + '. ' + o + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: oppText.slice(0, 1800) } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Notion | Powered by Exa + Firecrawl + Claude AI' }] });
const fallbackText = 'Competitor Research for ' + (ai.sourceCompany || $.input.sourceCompany) + ': ' + comps.length + ' competitors analyzed';
return { blocks, fallbackText };
